import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'

// MODEL

export const BadgeVariant = S.Union([
  S.Literal('default'),
  S.Literal('secondary'),
  S.Literal('destructive'),
  S.Literal('outline'),
  S.Literal('ghost'),
  S.Literal('link'),
])
export type BadgeVariant = typeof BadgeVariant.Type

export const badgeVariantValues: ReadonlyArray<BadgeVariant> = [
  'default',
  'secondary',
  'destructive',
  'outline',
  'ghost',
  'link',
]

export const BadgeStyleOptions = S.Struct({
  variant: S.optional(BadgeVariant),
  className: S.optional(S.String),
})
export type BadgeStyleOptions = typeof BadgeStyleOptions.Type

// VIEW

export type BadgeAttributes<Message> = Readonly<{
  badge: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = BadgeStyleOptions &
  Readonly<{
    toView: (attributes: BadgeAttributes<Message>) => Html
  }>

export const baseClassName =
  'group/badge inline-flex h-5 w-fit shrink-0 items-center justify-center gap-1 overflow-hidden rounded-4xl border border-transparent px-2 py-0.5 text-xs font-medium whitespace-nowrap transition-all focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&>svg]:pointer-events-none [&>svg]:size-3!'

export const rtlBaseClassName =
  'group/badge inline-flex h-5 w-fit shrink-0 items-center justify-center gap-1 overflow-hidden rounded-4xl border border-transparent px-2 py-0.5 text-xs font-medium whitespace-nowrap transition-all focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 has-data-[icon=inline-end]:pe-1.5 has-data-[icon=inline-start]:ps-1.5 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&>svg]:pointer-events-none [&>svg]:size-3!'

export const variantClassNames: Readonly<Record<BadgeVariant, string>> = {
  default: 'bg-primary text-primary-foreground [a]:hover:bg-primary/80',
  secondary: 'bg-secondary text-secondary-foreground [a]:hover:bg-secondary/80',
  destructive:
    'bg-destructive/10 text-destructive focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:focus-visible:ring-destructive/40 [a]:hover:bg-destructive/20',
  outline:
    'border-border text-foreground [a]:hover:bg-muted [a]:hover:text-muted-foreground',
  ghost: 'hover:bg-muted hover:text-muted-foreground dark:hover:bg-muted/50',
  link: 'text-primary underline-offset-4 hover:underline',
}

export const badgeVariants = ({
  variant = 'default',
  className,
}: BadgeStyleOptions = {}): string =>
  cn(baseClassName, variantClassNames[variant], className)

export const rtlBadgeVariants = ({
  variant = 'default',
  className,
}: BadgeStyleOptions = {}): string =>
  cn(rtlBaseClassName, variantClassNames[variant], className)

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  variant: BadgeVariant,
  className: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'badge'),
  h.DataAttribute('variant', variant),
  h.Class(cn(badgeVariants({ variant, className }))),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, variant = 'default', className } = config

  return toView({
    badge: shadcnAttributes(h, variant, className),
  })
}

import type { Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import type { BadgeVariant } from './index'
import { rtlBadgeVariants, view as Badge } from './index'

type IconPlacement = 'inline-start' | 'inline-end'

const icon = (
  className: string,
  path: string,
  placement?: IconPlacement,
): Html => {
  const h = html<never>()
  const placementAttributes =
    placement === undefined ? [] : [h.DataAttribute('icon', placement)]

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      h.Class(className),
      h.AriaHidden(true),
      ...placementAttributes,
    ],
    [h.path([h.D(path)], [])],
  )
}

const badgeCheckIcon = (placement: IconPlacement): Html =>
  icon(
    'lucide lucide-badge-check',
    'M3.85 8.62a4 4 0 0 1 4.78-4.77 4 4 0 0 1 6.74 0 4 4 0 0 1 4.78 4.78 4 4 0 0 1 0 6.74 4 4 0 0 1-4.77 4.78 4 4 0 0 1-6.75 0 4 4 0 0 1-4.78-4.77 4 4 0 0 1 0-6.76ZM9 12l2 2 4-4',
    placement,
  )

const bookmarkIcon = (placement: IconPlacement): Html =>
  icon(
    'lucide lucide-bookmark',
    'M19 21l-7-4-7 4V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2v16',
    placement,
  )

const arrowUpRightIcon = (placement: IconPlacement): Html =>
  icon('lucide lucide-arrow-up-right', 'M7 7h10v10M7 17 17 7', placement)

const spinner = (placement: IconPlacement): Html => {
  const h = html<never>()

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      h.DataAttribute('slot', 'spinner'),
      h.DataAttribute('icon', placement),
      h.Role('status'),
      h.AriaLabel('Loading'),
      h.Class('lucide lucide-loader-circle size-4 animate-spin'),
    ],
    [h.path([h.D('M21 12a9 9 0 1 1-6.219-8.56')], [])],
  )
}

const arabicBadgeRtl = {
  dir: 'rtl',
  values: {
    badge: 'شارة',
    secondary: 'ثانوي',
    destructive: 'مدمر',
    outline: 'مخطط',
    verified: 'متحقق',
    bookmark: 'إشارة مرجعية',
  },
}

const RtlBadge = (
  variant: BadgeVariant,
  children: ReadonlyArray<Html | string>,
): Html => {
  const h = html<never>()

  return h.span(
    [
      h.Class(rtlBadgeVariants({ variant })),
      h.DataAttribute('slot', 'badge'),
      h.DataAttribute('variant', variant),
    ],
    children,
  )
}

export const BadgeColors = (): Html => {
  const h = html<never>()
  const customColorBadge = (className: string, label: string): Html =>
    Badge<never>({
      className,
      toView: attributes => h.span([...attributes.badge], [label]),
    })

  return h.div(
    [h.Class('flex flex-wrap gap-2')],
    [
      customColorBadge(
        'bg-blue-50 text-blue-700 dark:bg-blue-950 dark:text-blue-300',
        'Blue',
      ),
      customColorBadge(
        'bg-green-50 text-green-700 dark:bg-green-950 dark:text-green-300',
        'Green',
      ),
      customColorBadge(
        'bg-sky-50 text-sky-700 dark:bg-sky-950 dark:text-sky-300',
        'Sky',
      ),
      customColorBadge(
        'bg-purple-50 text-purple-700 dark:bg-purple-950 dark:text-purple-300',
        'Purple',
      ),
      customColorBadge(
        'bg-red-50 text-red-700 dark:bg-red-950 dark:text-red-300',
        'Red',
      ),
    ],
  )
}

export const BadgeDemo = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex w-full flex-wrap justify-center gap-2')],
    [
      Badge<never>({
        toView: attributes => h.span([...attributes.badge], ['Badge']),
      }),
      Badge<never>({
        variant: 'secondary',
        toView: attributes => h.span([...attributes.badge], ['Secondary']),
      }),
      Badge<never>({
        variant: 'destructive',
        toView: attributes => h.span([...attributes.badge], ['Destructive']),
      }),
      Badge<never>({
        variant: 'outline',
        toView: attributes => h.span([...attributes.badge], ['Outline']),
      }),
    ],
  )
}

export const BadgeIcon = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex flex-wrap gap-2')],
    [
      Badge<never>({
        variant: 'secondary',
        toView: attributes =>
          h.span(
            [...attributes.badge],
            [badgeCheckIcon('inline-start'), 'Verified'],
          ),
      }),
      Badge<never>({
        variant: 'outline',
        toView: attributes =>
          h.span(
            [...attributes.badge],
            ['Bookmark', bookmarkIcon('inline-end')],
          ),
      }),
    ],
  )
}

export const BadgeLink = (): Html => {
  const h = html<never>()

  return Badge<never>({
    toView: attributes =>
      h.a(
        [...attributes.badge, h.Href('#link')],
        ['Open Link ', arrowUpRightIcon('inline-end')],
      ),
  })
}

export const BadgeRtl = (): Html => {
  const h = html<never>()
  const { dir, values } = arabicBadgeRtl

  return h.div(
    [h.Class('flex w-full flex-wrap justify-center gap-2'), h.Dir(dir)],
    [
      RtlBadge('default', [values.badge]),
      RtlBadge('secondary', [values.secondary]),
      RtlBadge('destructive', [values.destructive]),
      RtlBadge('outline', [values.outline]),
      RtlBadge('secondary', [badgeCheckIcon('inline-start'), values.verified]),
      RtlBadge('outline', [values.bookmark, bookmarkIcon('inline-end')]),
    ],
  )
}

export const BadgeSpinner = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex flex-wrap gap-2')],
    [
      Badge<never>({
        variant: 'destructive',
        toView: attributes =>
          h.span([...attributes.badge], [spinner('inline-start'), 'Deleting']),
      }),
      Badge<never>({
        variant: 'secondary',
        toView: attributes =>
          h.span([...attributes.badge], ['Generating', spinner('inline-end')]),
      }),
    ],
  )
}

export const BadgeVariants = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex flex-wrap gap-2')],
    [
      Badge<never>({
        toView: attributes => h.span([...attributes.badge], ['Default']),
      }),
      Badge<never>({
        variant: 'secondary',
        toView: attributes => h.span([...attributes.badge], ['Secondary']),
      }),
      Badge<never>({
        variant: 'destructive',
        toView: attributes => h.span([...attributes.badge], ['Destructive']),
      }),
      Badge<never>({
        variant: 'outline',
        toView: attributes => h.span([...attributes.badge], ['Outline']),
      }),
      Badge<never>({
        variant: 'ghost',
        toView: attributes => h.span([...attributes.badge], ['Ghost']),
      }),
    ],
  )
}

